document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll("#webs .webs-card").forEach(e=>{const t=e.querySelectorAll(".device-selector button"),n=e.querySelectorAll(".device");t.forEach(e=>{e.addEventListener("click",s=>{s.stopPropagation();const o=e.dataset.target;n.forEach(e=>e.classList.toggle("active",e.dataset.device===o)),t.forEach(e=>e.classList.remove("active")),e.classList.add("active")})}),e.addEventListener("click",()=>{const t=e.dataset.url;t&&window.open(t,"_blank","noopener,noreferrer")}),e.style.cursor="pointer"}),document.querySelectorAll(".clickeable-card").forEach(e=>{const t=e.dataset.url;if(!t)return;e.addEventListener("click",()=>{window.location.href=t}),e.style.cursor="pointer"})})